+    // =========================================================================
+    // Diagnostics tests
+    // =========================================================================
+
+    #[test]
+    fn diagnostics_captures_theme_state() {
+        let theme = TableTheme::aurora().with_padding(4).with_effect(TableEffectRule::new(
+            TableEffectTarget::AllRows,
+            pulse_effect(PackedRgba::RED, PackedRgba::BLACK),
+        ));
