+    // TableEffectScope tests
+    // =========================================================================
+
+    #[test]
+    fn scope_section_has_no_row_or_column() {
+        let s = TableEffectScope::section(TableSection::Header);
+        assert_eq!(s.section, TableSection::Header);
+        assert_eq!(s.row, None);
